const body = $input.first().json.body || $input.first().json;
const kbId = body.kbId;
const sourceUrl = String(body.sourceUrl || '').trim();
const sourceTypeRaw = String(body.sourceType || '').trim().toLowerCase();
const sourceType = sourceTypeRaw === 'gdrive' || sourceTypeRaw === 'google' ? 'googledrive' : sourceTypeRaw;
const sourceBranch = body.sourceBranch || 'main';
const sourcePath = body.sourcePath || '';
const sourcePaths = Array.isArray(body.sourcePaths) ? body.sourcePaths : [];
const difyDatasetId = body.difyDatasetId;
const difyApiUrl = body.difyApiUrl || 'http://dify-api:5001';
const difyApiKey = body.difyApiKey || '';
const syncJobId = body.syncJobId;
const progressCallbackUrl = body.progressCallbackUrl;
const progressCallbackToken = body.progressCallbackToken || '';
const sourceToken = body.sourceToken || '';
const sourceRefreshToken = body.sourceRefreshToken || '';

if (!kbId || !sourceUrl || !difyDatasetId || !syncJobId || !difyApiKey) {
  throw new Error('Missing required sync parameters');
}
if (!['github', 'gitlab', 'googledrive'].includes(sourceType)) {
  throw new Error('Unsupported generic sync sourceType: ' + (sourceType || '<empty>'));
}

const params = {
  kbId,
  provider: sourceType,
  sourceType,
  sourceUrl,
  branch: sourceBranch,
  path: sourcePath,
  sourcePaths,
  difyDatasetId,
  difyApiUrl,
  difyApiKey,
  syncJobId,
  progressCallbackUrl,
  progressCallbackToken,
  sourceToken,
  sourceRefreshToken,
  syncStartedAt: new Date().toISOString()
};

if (sourceType === 'github') {
  const match = sourceUrl.match(/github\.com\/([^/]+)\/([^/#?]+)/i);
  if (!match) throw new Error('Invalid GitHub URL: ' + sourceUrl);
  params.owner = match[1];
  params.repo = match[2].replace(/\.git$/i, '');
} else if (sourceType === 'gitlab') {
  const match = sourceUrl.match(/gitlab\.com\/([^?#]+?)(?:\/-\/.*)?$/i);
  if (!match) throw new Error('Invalid GitLab URL: ' + sourceUrl);
  params.projectPath = match[1].replace(/\.git$/i, '').replace(/\/+$/g, '');
  params.encodedProjectPath = encodeURIComponent(params.projectPath);
} else if (sourceType === 'googledrive') {
  const folderMatch = sourceUrl.match(/\/folders\/([a-zA-Z0-9_-]+)/) || sourceUrl.match(/[?&]id=([a-zA-Z0-9_-]+)/);
  if (!folderMatch) throw new Error('Invalid Google Drive folder URL: ' + sourceUrl);
  if (!sourceToken) throw new Error('Google Drive sync requires an OAuth access token. Reconnect the integration and try again.');
  params.driveFolderId = folderMatch[1];
}

return [{ json: params }];

const items = $input.all();
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await this.helpers.httpRequest({
