      },
      json: true,
    });
  } catch {}
}
return items;

const params = $('Parse Sync Params').first().json;

function authHeaders() {
  if (params.provider === 'github') {
    return {
      Accept: 'application/vnd.github+json',
      'User-Agent': 'platform-rag-sync/1.0',
      ...(params.sourceToken ? { Authorization: 'token ' + params.sourceToken } : {})
    };
  }
  if (params.provider === 'gitlab') {
    return {
      'User-Agent': 'platform-rag-sync/1.0',
      ...(params.sourceToken ? { Authorization: 'Bearer ' + params.sourceToken } : {})
    };
  }
  return {
    Authorization: 'Bearer ' + params.sourceToken,
    Accept: 'application/json'
  };
}

async function requestJson(options, label) {
  try {
    return await this.helpers.httpRequest({ ...options, json: true, returnFullResponse: false });
  } catch (error) {
    const status = error?.response?.statusCode || error?.statusCode || '';
    const body = error?.response?.body;
    const detail = typeof body === 'string' ? body : (body?.message || body?.error || error?.message || String(error));
    throw new Error(label + ' failed' + (status ? ' HTTP ' + status : '') + ': ' + detail);
  }
}

async function listGitHub() {
  const tree = await requestJson.call(this, {
    method: 'GET',
    url: 'https://api.github.com/repos/' + encodeURIComponent(params.owner) + '/' + encodeURIComponent(params.repo) + '/git/trees/' + encodeURIComponent(params.branch) + '?recursive=1',
    headers: authHeaders()
  }, 'GitHub file tree');
  if (tree.truncated) throw new Error('GitHub repository tree exceeds 100,000 files and was truncated. Use a more specific source path to limit the scope.');
  return (tree.tree || []).map(file => ({
    path: file.path,
    type: file.type,
    sha: file.sha
  }));
}

async function listGitLab() {
  const filterPaths = (params.sourcePaths && params.sourcePaths.length > 0) ? params.sourcePaths : (params.path ? [params.path] : [null]);
  const files = [];
  for (const filterPath of filterPaths) {
    for (let page = 1; page <= 100; page++) {
      let url = 'https://gitlab.com/api/v4/projects/' + params.encodedProjectPath + '/repository/tree?ref=' + encodeURIComponent(params.branch) + '&recursive=true&per_page=100&page=' + page;
      if (filterPath) url += '&path=' + encodeURIComponent(filterPath);
      const pageFiles = await requestJson.call(this, { method: 'GET', url, headers: authHeaders() }, 'GitLab file tree');
      for (const file of pageFiles || []) {
        files.push({ path: file.path, type: file.type === 'tree' ? 'tree' : 'blob', sha: file.id || file.sha || file.path });
      }
      if (!Array.isArray(pageFiles) || pageFiles.length < 100) break;
    }
  }
  return files;
}

const GOOGLE_EXPORTS = {
  'application/vnd.google-apps.document': { ext: 'docx', mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' },
  'application/vnd.google-apps.spreadsheet': { ext: 'xlsx', mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' },
  'application/vnd.google-apps.presentation': { ext: 'pptx', mimeType: 'application/vnd.openxmlformats-officedocument.presentationml.presentation' }
};

function drivePath(prefix, name, exportInfo) {
  const cleanName = String(name || 'untitled').replace(/[\\/]+/g, '-');
  if (!exportInfo) return prefix ? prefix + '/' + cleanName : cleanName;
  const withoutGoogleExt = cleanName.replace(/\.[^.]+$/, '');
  return (prefix ? prefix + '/' : '') + withoutGoogleExt + '.' + exportInfo.ext;
}

async function listDriveFolder(folderId, prefix = '', depth = 0) {
  if (depth > 12) return [];
  const all = [];
  let pageToken = '';
  do {
    const query = encodeURIComponent("'" + folderId + "' in parents and trashed = false");
    const fields = encodeURIComponent('nextPageToken,files(id,name,mimeType,modifiedTime,md5Checksum,size)');
    const url = 'https://www.googleapis.com/drive/v3/files?q=' + query + '&fields=' + fields + '&pageSize=1000' + (pageToken ? '&pageToken=' + encodeURIComponent(pageToken) : '');
    const data = await requestJson.call(this, { method: 'GET', url, headers: authHeaders() }, 'Google Drive file list');
    for (const file of data.files || []) {
      if (file.mimeType === 'application/vnd.google-apps.folder') {
        all.push(...await listDriveFolder.call(this, file.id, prefix ? prefix + '/' + file.name : file.name, depth + 1));
        continue;
      }
      const exportInfo = GOOGLE_EXPORTS[file.mimeType] || null;
      const path = drivePath(prefix, file.name, exportInfo);
      all.push({
        path,
        type: 'blob',
        sha: [file.id, file.modifiedTime || '', file.md5Checksum || file.size || '', exportInfo?.ext || ''].join(':'),
      });
    }
    pageToken = data.nextPageToken || '';
  } while (pageToken);
  return all;
}

let tree;
if (params.provider === 'github') tree = await listGitHub.call(this);
else if (params.provider === 'gitlab') tree = await listGitLab.call(this);
else tree = await listDriveFolder.call(this, params.driveFolderId);

return [{ json: { ...params, tree } }];

const input = $input.first();
const params = $('Parse Sync Params').first().json;

// When continueOnFail=true, failed HTTP nodes put the error on json
const statusCode = input.json.statusCode || 0;
const hasError = !!input.json.error || statusCode >= 400;

if (hasError) {
  const rawMsg = input.json.message || input.json.error || 'Failed to fetch source file list';
  const displayMsg = statusCode ? 'HTTP ' + statusCode + ': ' + rawMsg : rawMsg;

  if (params.progressCallbackUrl) {
    const headers = { 'Content-Type': 'application/json' };
    if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: params.progressCallbackUrl,
        headers,
        body: {
          syncJobId: params.syncJobId,
          status: 'failed',
          errorMessage: displayMsg,
          step: {
            task: 'List Source Files',
            stepName: 'fetch_file_tree',
            status: 'failed',
            completedAt: new Date().toISOString(),
            errorMessage: displayMsg,
          },
          logMessage: 'List Source Files failed: ' + displayMsg,
          logSeverity: 'ERROR',
        },
        json: true,
      });
    } catch {}
  }
  throw new Error('List Source Files failed: ' + displayMsg);
}

return [$input.first()];

const response = $input.first().json;
const params = $('Parse Sync Params').first().json;
const skippedFiles = response.skippedFiles || [];

if (skippedFiles.length > 0 && params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;

  const byExt = {};
  for (const f of skippedFiles) {
    const ext = f.ext || 'unknown';
    byExt[ext] = (byExt[ext] || 0) + 1;
  }
  const extSummary = Object.entries(byExt)
    .map(([ext, cnt]) => `.${ext} (${cnt})`)
    .join(', ');

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'running',
        step: {
          task: 'Filter Files',
          stepName: 'filter_extensions',
          status: 'completed',
          completedAt: new Date().toISOString(),
          message: `Skipped ${skippedFiles.length} file(s) — unsupported format: ${extSummary}`,
        },
        logMessage: `Skipped ${skippedFiles.length} unsupported file(s): ${extSummary}`,
        logSeverity: 'INFO',
      },
      json: true,
    });
  } catch {}
}

return $input.all();

const response = $input.first().json || {};
const params = $('Parse Sync Params').first().json;

// Handle if the sync-diff node returned an error directly
if (response.error || response.message) {
  if (params.progressCallbackUrl) {
    const headers = { 'Content-Type': 'application/json' };
    if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
    this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'failed',
        errorMessage: String(response.error || response.message || 'Error communicating with gateway'),
        logSeverity: 'ERROR',
      },
      json: true,
    }).catch(() => {});
  }
  throw new Error(String(response.error || response.message || 'Error communicating with gateway'));
}

const files = response.files || [];

if (files.length === 0) {
  if (params.progressCallbackUrl) {
    const headers = { 'Content-Type': 'application/json' };
    if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
    // First mark Fetch File Tree as completed so it doesn't stay 'running'
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'running',
        filesProcessed: 0,
        filesTotal: 0,
        step: {
          task: 'Fetch File Tree',
          stepName: 'fetch_file_tree',
          status: 'completed',
          completedAt: new Date().toISOString(),
          message: 'No files to update',
        },
      },
      json: true,
    }).catch(() => {});
    // Then report the skip-sync completion
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'completed',
        filesProcessed: 0,
        filesTotal: 0,
        step: {
          task: 'Skip Sync',
          stepName: 'skip_sync',
          status: 'completed',
          completedAt: new Date().toISOString(),
          message: 'No files needed updating or creating',
        },
        logMessage: 'Sync complete: No files modified since last sync',
        logSeverity: 'INFO',
      },
      json: true,
    }).catch(() => {});
  }
  return [];
}

return files.map((item, index) => ({
  json: {
    ...params,
    provider: params.provider,
    filePath: item.path,
    fileSha: item.sha,
    fileExt: (item.path.split('.').pop() || '').toLowerCase(),
    fileIndex: index + 1,
    totalFiles: files.length,
    difyDocumentId: item.difyDocumentId || null,
    isUpdate: !!item.isUpdate
  }
}));

